import java.util.Scanner;

public class XSSVulnerableCode {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter your name: ");
        String userInput = scanner.nextLine();

        // Improperly handling user input by directly concatenating it into the HTML response
        String htmlResponse = "<p>Welcome, " + userInput + "!</p>";

        // Vulnerability: If the user inputs malicious script tags, it will be executed in other users' browsers
        System.out.println(htmlResponse);
    }
}

